UNIQUE(email, app_id), UNIQUE(username, app_id),
CONSTRAINT fk_app FOREIGN KEY (app_id) REFERENCES apps (id) ON DELETE CASCADE );
CREATE INDEX IF NOT EXISTS idx_email ON users (app_id, email);

