ON CONFLICT DO NOTHING;

package suite

import (
	"context"
	"errors"
	"net"
	"os"
	"strconv"
	"strings"
	"testing"
	"time"

	"github.com/brianvoe/gofakeit/v7"
	"github.com/joho/godotenv"
	"github.com/synnfluxx/TrustMeBroID/internal/config"
	ssov1 "gitlab.com/synnfluxx/protos/sso/gen"
	"google.golang.org/grpc"
	"google.golang.org/grpc/credentials/insecure"
	"google.golang.org/grpc/metadata"
)

const (
	grpcHost = "localhost"
)

type Suite struct {
	*testing.T
	Cfg        *config.Config
	AuthClient ssov1.AuthClient
	AppID      int64
	AppSecret  string
}

func New(t *testing.T) (context.Context, *Suite) {
	t.Helper()
	t.Parallel()

	_ = godotenv.Load("../.env", ".env")
	cfg := config.MustLoadByPath("../config/local.yaml")

	ctx, cancelCtx := context.WithTimeout(context.Background(), cfg.GRPC.Timeout)

	cc, err := grpc.NewClient(grpcAddress(cfg), grpc.WithTransportCredentials(insecure.NewCredentials()))
	if err != nil {
		t.Fatalf("grpc server connection failed: %v", err)
	}

	authClient := ssov1.NewAuthClient(cc)
	appName := "test-" + gofakeit.LetterN(8) + strconv.FormatInt(time.Now().UnixNano(), 10)
	appRedirectURI := "http://localhost:3000/auth/callback"

	resp, err := authClient.RegisterApp(adminContext(context.Background()), &ssov1.RegisterAppRequest{
		AppName:     appName,
		RedirectUri: appRedirectURI,
	})
	if err != nil {
		if serverUnavailable(err) {
			cancelCtx()
			_ = cc.Close()
			t.Skipf("integration server is unavailable at %s: %v", grpcAddress(cfg), err)
		}
		t.Fatalf("test app creating error: %v", err)
	}

	t.Cleanup(func() {
		t.Helper()
		cancelCtx()
		_ = cc.Close()

		if _, err := authClient.DeleteApp(adminContext(context.Background()), &ssov1.DeleteAppRequest{
			AppId: resp.AppId,
		}); err != nil {
			t.Fatalf("error while deleting app: %v", err)
		}
	})

	return ctx, &Suite{
		T:          t,
		Cfg:        cfg,
		AuthClient: ssov1.NewAuthClient(cc),
		AppID:      resp.GetAppId(),
		AppSecret:  resp.GetSecret(),
	}
}

func grpcAddress(cfg *config.Config) string {
	return net.JoinHostPort(grpcHost, strconv.Itoa(int(cfg.GRPC.Port)))
}

func adminContext(ctx context.Context) context.Context {
	return metadata.AppendToOutgoingContext(ctx, "x-admin-token", os.Getenv("ADMIN_TOKEN"))
}

func serverUnavailable(err error) bool {
	if err == nil {
		return false
	}

	return errors.Is(err, context.DeadlineExceeded) ||
		strings.Contains(err.Error(), "connection refused") ||
		strings.Contains(err.Error(), "connection error") ||
		strings.Contains(err.Error(), "Error while dialing")
}

package tests

import (
	"strconv"
	"testing"
	"time"

	"github.com/brianvoe/gofakeit/v7"
	"github.com/golang-jwt/jwt/v5"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"github.com/synnfluxx/TrustMeBroID/tests/suite"
	ssov1 "gitlab.com/synnfluxx/protos/sso/gen"
)

const (
	passDefaultLen = 10
	deltaSeconds   = 10
)

func TestRegisterLogin_Login_HappyPath(t *testing.T) {
	ctx, st := suite.New(t)

	email := gofakeit.Email()
	username := gofakeit.Username()
	pw := fakePassword()

	resp, err := st.AuthClient.Register(ctx, &ssov1.RegisterRequest{
		Email:    email,
		Username: username,
		Password: pw,
		AppId:    st.AppID,
	})
	require.NoError(t, err)
	assert.NotEmpty(t, resp.GetUserId())

	respLogin, err := st.AuthClient.Login(ctx, &ssov1.LoginRequest{
		Identifier: &ssov1.LoginRequest_Email{
			Email: email,
		},
		Password: pw,
		AppId:    st.AppID,
	})

	loginTime := time.Now()

	require.NoError(t, err)
	assert.NotEmpty(t, respLogin.GetAccessToken())
	assert.NotEmpty(t, respLogin.GetRefreshToken())

	refreshToken := respLogin.GetRefreshToken()
	refreshClaims := &jwt.RegisteredClaims{}
	refreshTokenParsed, err := jwt.ParseWithClaims(refreshToken, refreshClaims, func(token *jwt.Token) (any, error) {
		return []byte(st.AppSecret), nil
	})
	require.NoError(t, err)
	require.True(t, refreshTokenParsed.Valid)

	uid, err := jwtSubjectToInt64(refreshClaims.Subject)
	require.NoError(t, err)

	assert.Equal(t, resp.GetUserId(), uid)
	assert.Equal(t, int64ToString(st.AppID), refreshClaims.Issuer)

	assert.InDelta(t, loginTime.Add(st.Cfg.RefreshTokenTTL).Unix(), refreshClaims.ExpiresAt.Unix(), deltaSeconds)

	token := respLogin.GetAccessToken()
	claims := &jwt.RegisteredClaims{}
	tokenParsed, err := jwt.ParseWithClaims(token, claims, func(token *jwt.Token) (any, error) {
		return []byte(st.AppSecret), nil
	})
	require.NoError(t, err)
	require.True(t, tokenParsed.Valid)

	uid, err = jwtSubjectToInt64(claims.Subject)
	require.NoError(t, err)

	assert.Equal(t, resp.GetUserId(), uid)
	assert.Equal(t, int64ToString(st.AppID), claims.Issuer)

	assert.InDelta(t, loginTime.Add(st.Cfg.AccessTokenTTL).Unix(), claims.ExpiresAt.Unix(), deltaSeconds)
}

func TestRegisterLogin_Login_DuplicateRegistration(t *testing.T) {
	ctx, st := suite.New(t)

	email := gofakeit.Email()
	username := gofakeit.Username()
	pw := fakePassword()

	resp, err := st.AuthClient.Register(ctx, &ssov1.RegisterRequest{
		Email:    email,
		Username: username,
		Password: pw,
		AppId:    st.AppID,
	})
	require.NoError(t, err)
	assert.NotEmpty(t, resp.GetUserId())

	_, err = st.AuthClient.Register(ctx, &ssov1.RegisterRequest{
		Email:    email,
		Username: username,
		Password: pw,
		AppId:    st.AppID,
	})
	require.Error(t, err)
	assert.Contains(t, err.Error(), "already exists")
}

func fakePassword() string {
	return gofakeit.Password(true, true, true, true, false, passDefaultLen)
}

func jwtSubjectToInt64(subject string) (int64, error) {
	return strconv.ParseInt(subject, 10, 64)
}

func int64ToString(v int64) string {
	return strconv.FormatInt(v, 10)
}

package grpcApp

import (
	"context"
	"log/slog"
	"slices"
	"time"

	ssov1 "gitlab.com/synnfluxx/protos/sso/gen"
	"golang.org/x/time/rate"
	"google.golang.org/grpc"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/metadata"
	"google.golang.org/grpc/status"
)

var adminMethods = []string{
	ssov1.Auth_RegisterApp_FullMethodName,
	ssov1.Auth_DeleteUser_FullMethodName,
	ssov1.Auth_DeleteAdmin_FullMethodName,
	ssov1.Auth_DeleteApp_FullMethodName,
	ssov1.Auth_UpdateRefreshToken_FullMethodName,
	ssov1.Auth_MakeAdmin_FullMethodName,
	ssov1.Auth_Logout_FullMethodName,
}

func isAdminMethod(method string) bool {
	return slices.Contains(adminMethods, method)
}

func AdminRequestsInterceptor() grpc.UnaryServerInterceptor {
	return func(ctx context.Context, req any, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (resp any, err error) {
		if isAdminMethod(info.FullMethod) {
			md, ok := metadata.FromIncomingContext(ctx)
			if !ok {
				return nil, status.Error(codes.PermissionDenied, "error while extracting metadata")
			}

			tokens := md["x-admin-token"]
			if len(tokens) == 0 {
				return nil, status.Error(codes.PermissionDenied, "auth endpoinds must be with x-admin-token field")
			}

			if !validateToken(tokens[0]) {
				return nil, status.Error(codes.PermissionDenied, "invalid token")
			}
		}

		return handler(ctx, req)
	}
}

func LoggerInterceptor(log *slog.Logger) grpc.UnaryServerInterceptor {
	return func(ctx context.Context, req any, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (resp any, err error) {
		start := time.Now()

		resp, err = handler(ctx, req)
		duration := time.Since(start)

		if err != nil {
			log.Error("grpc request", "method", info.FullMethod, "duration", duration.Milliseconds(), "error", err)
		} else {
			log.Info("grpc request", "method", info.FullMethod, "duration", duration.Milliseconds())
		}

		return resp, err
	}
}

func RateLimiterInterceptor(limiter *rate.Limiter) grpc.UnaryServerInterceptor {
	return func(ctx context.Context, req any, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (resp any, err error) {
		if !limiter.Allow() {
			return nil, status.Errorf(codes.ResourceExhausted, "%s have been rejected by rate limiting.", info.FullMethod)
		}

		return handler(ctx, req)
	}
}

package grpcApp

import (
	"context"
	"crypto/subtle"
	"fmt"
	"log/slog"
	"net"
	"os"

	authgrpc "github.com/synnfluxx/TrustMeBroID/internal/grpc/auth"
	"golang.org/x/time/rate"
	"google.golang.org/grpc"
	"google.golang.org/grpc/reflection"
)

type App struct {
	log          *slog.Logger
	gRPCServer   *grpc.Server
	port         int
	ReaperCancel context.CancelFunc
}

func New(log *slog.Logger, authService authgrpc.Auth, port int, cancel context.CancelFunc, rps, burst int) *App {
	gRPCServer := grpc.NewServer(grpc.ChainUnaryInterceptor(RateLimiterInterceptor(rate.NewLimiter(rate.Limit(rps), burst)), LoggerInterceptor(log), AdminRequestsInterceptor()))

	authgrpc.Register(gRPCServer, authService)
	reflection.Register(gRPCServer)

	return &App{
		log:          log,
		gRPCServer:   gRPCServer,
		port:         port,
		ReaperCancel: cancel,
	}
}

func (a *App) MustRun() {
	if err := a.Run(); err != nil {
		panic(err)
	}
}

func (a *App) Run() error {
	const op = "grpcapp.Run"

	log := a.log.With(slog.String("op", op), slog.Int("port", a.port))

	l, err := net.Listen("tcp", fmt.Sprintf(":%d", a.port))
	if err != nil {
		return fmt.Errorf("%s: %w", op, err)
	}

	log.Info("grpc server is running", slog.String("addr", l.Addr().String()))

	if err := a.gRPCServer.Serve(l); err != nil {
		return fmt.Errorf("%s: %w", op, err)
	}

	return nil
}

func (a *App) Stop() {
	const op = "grpcapp.Stop"

	a.log.With(slog.String("op", op)).Info("stopping gRPC server", slog.Int("port", a.port))

	a.gRPCServer.GracefulStop()
	a.ReaperCancel()
}

func validateToken(token string) bool {
	if token == "" {
		return false
	}
	return subtle.ConstantTimeCompare([]byte(os.Getenv("ADMIN_TOKEN")), []byte(token)) == 1
}

package app

import (
	"context"
	"fmt"
	"log/slog"
	"time"

	grpcApp "github.com/synnfluxx/TrustMeBroID/internal/app/grpc"
	httpApp "github.com/synnfluxx/TrustMeBroID/internal/app/http"
	"github.com/synnfluxx/TrustMeBroID/internal/lib/encryptor"
	"github.com/synnfluxx/TrustMeBroID/internal/lib/logger/sl"
	"github.com/synnfluxx/TrustMeBroID/internal/services/auth"
	"github.com/synnfluxx/TrustMeBroID/internal/storage/postgres"
	redisStorage "github.com/synnfluxx/TrustMeBroID/internal/storage/redis"
)

type App struct {
	GRPCSrv *grpcApp.App
	HTTPSrv *httpApp.App
}

func New(log *slog.Logger, grpcPort, grpcRPS, grpcBurst, httpRPS, httpBurst int, storagePath string, redisPort, redisRetries int, redisHost string, redisTimeout, accessTokenTTL, refreshTokenTTL, reaperDelay, visitorCleanerDelay time.Duration) *App {
	storage, err := postgres.New(storagePath)
	if err != nil {
		panic(err)
	}

	redis, err := redisStorage.NewRedis(fmt.Sprintf("%s:%d", redisHost, redisPort), redisTimeout, redisRetries)
	if err != nil {
		panic(err)
	}

	ctx, cancel := context.WithCancel(context.Background())
	go func(ctx context.Context) {
		ticker := time.NewTicker(reaperDelay)
		defer ticker.Stop()
		for {
			select {
			case <-ctx.Done():
				return
			case <-ticker.C:
				log.Info("Trying to delete old RIP users")
				deleted, err := storage.Reaper(context.Background())
				if err != nil {
					log.Warn("storage reaper error", sl.Err(err))
				} else {
					log.Info("storage reaper deleted successfully with users", slog.Attr{Key: "deleted users", Value: slog.AnyValue(deleted)})
				}
			}
		}
	}(ctx)

	ph := encryptor.NewPasswordHasher()
	authService := auth.New(log, storage, storage, storage, storage, redis, ph, accessTokenTTL, refreshTokenTTL)

	return &App{
		GRPCSrv: grpcApp.New(log, authService, grpcPort, cancel, grpcRPS, grpcBurst),
		HTTPSrv: httpApp.NewHTTPApp(storage, log, redis, accessTokenTTL, refreshTokenTTL, visitorCleanerDelay, httpRPS, httpBurst),
	}
}

package httpApp

import (
	"context"
	"errors"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"sync"
	"sync/atomic"
	"time"

	"github.com/google/uuid"
	"github.com/gorilla/mux"
	"github.com/mo7zayed/reqip"
	"github.com/synnfluxx/TrustMeBroID/internal/http/handlers"
	"github.com/synnfluxx/TrustMeBroID/internal/services/oauth"
	"golang.org/x/time/rate"
)

type App struct {
	router        *mux.Router
	log           *slog.Logger
	bindAddr      string
	srv           *http.Server
	oAuthServer   GitHubOAuthServer
	visitors      map[string]*Visitor
	mu            sync.RWMutex
	rps           int
	burst         int
	cleanerCancel context.CancelFunc
}

type Visitor struct {
	limiter  *rate.Limiter
	lastSeen atomic.Int64
}

type ctxKey int8

const (
	ctxKeyUser ctxKey = iota
	ctxKeyRequestID
)

type GitHubOAuthServer interface {
	CallbackHandler() http.HandlerFunc
	LoginHandler() http.HandlerFunc
}

func NewHTTPApp(storage oauth.Storage, log *slog.Logger, db oauth.TokenProvider, accessTTL, refreshTTL, cleanerDelay time.Duration, rps, burst int) *App {
	bindAddr := os.Getenv("HTTP_BIND_ADDR")

	GitHubOAuthService := oauth.New(oauth.NewGithubConfig(), storage, db, log)

	app := &App{
		router:      mux.NewRouter(),
		log:         log,
		bindAddr:    bindAddr,
		oAuthServer: handlers.NewHTTPOAuthServer(GitHubOAuthService, log, accessTTL, refreshTTL),
		visitors:    make(map[string]*Visitor),
		rps:         rps,
		burst:       burst,
	}

	app.configureRouter()
	app.srv = &http.Server{Addr: bindAddr, Handler: app}
	app.cleanerCancel = app.VisitorsCleaner(context.Background(), cleanerDelay)
	return app
}

func (a *App) configureRouter() {
	a.router.Use(a.setRequestID)
	a.router.Use(a.logRequest)
	a.router.Use(a.limit)
	a.router.HandleFunc(fmt.Sprintf("/auth/%s/login", "github"), a.oAuthServer.LoginHandler())
	a.router.HandleFunc(fmt.Sprintf("/auth/%s/callback", "github"), a.oAuthServer.CallbackHandler())
}

func (a *App) VisitorsCleaner(pctx context.Context, cleanerDelay time.Duration) context.CancelFunc {
	ctx, cancel := context.WithCancel(pctx)

	go func(ctx context.Context) {
		ticker := time.NewTicker(cleanerDelay)
		defer ticker.Stop()
		for {
			select {
			case <-ctx.Done():
				return
			case <-ticker.C:
				a.mu.Lock()
				for k, v := range a.visitors {
					if time.Since(time.Unix(v.lastSeen.Load(), 0)) >= 3*time.Hour {
						delete(a.visitors, k)
					}
				}
				a.mu.Unlock()
			}
		}
	}(ctx)

	return cancel
}

func (a *App) getVisitor(ip string) *Visitor {
	a.mu.RLock()
	visitor, ok := a.visitors[ip]
	a.mu.RUnlock()

	if ok {
		return visitor
	}

	a.mu.Lock()
	defer a.mu.Unlock()
	if visitor, ok := a.visitors[ip]; !ok {
		visitor = &Visitor{
			limiter: rate.NewLimiter(rate.Limit(a.rps), a.burst),
		}
		visitor.lastSeen.Store(time.Now().Unix())
		a.visitors[ip] = visitor
		return visitor
	} else {
		return visitor
	}
}

func (a *App) limit(next http.Handler) http.Handler {
	return http.HandlerFunc(
		func(w http.ResponseWriter, r *http.Request) {
			ip := reqip.GetClientIP(r)

			visitor := a.getVisitor(ip)
			visitor.lastSeen.Store(time.Now().Unix())
			if !visitor.limiter.Allow() {
				http.Error(w, http.StatusText(429), http.StatusTooManyRequests)
				return
			}

			next.ServeHTTP(w, r)
		})
}

func (a *App) setRequestID(next http.Handler) http.Handler {
	return http.HandlerFunc(
		func(w http.ResponseWriter, r *http.Request) {
			id := uuid.New().String()
			w.Header().Set("X-Request-ID", id)
			next.ServeHTTP(w, r.WithContext(context.WithValue(r.Context(), ctxKeyRequestID, id)))
		})
}

func (a *App) logRequest(next http.Handler) http.Handler {
	return http.HandlerFunc(
		func(w http.ResponseWriter, r *http.Request) {
			log := a.log.With("http request", "remote_addr", r.RemoteAddr, "request_id", r.Context().Value(ctxKeyRequestID))
			log.Info("started", "method", r.Method, "URI", r.RequestURI)
			start := time.Now()
			rw := &responseWriter{http.StatusOK, w}
			next.ServeHTTP(rw, r)

			switch {
			case rw.code >= 500:
				log.Error("request completed", "code", rw.code, "status", http.StatusText(rw.code), "duration", time.Since(start).Milliseconds())
			case rw.code >= 400:
				log.Warn("request completed", "code", rw.code, "status", http.StatusText(rw.code), "duration", time.Since(start).Milliseconds())
			default:
				log.Info("request completed", "code", rw.code, "status", http.StatusText(rw.code), "duration", time.Since(start).Milliseconds())
			}

		},
	)
}

func (a *App) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	a.router.ServeHTTP(w, r)
}

func (a *App) MustRun() {
	if err := a.Run(); err != nil {
		if errors.Is(err, http.ErrServerClosed) {
			return
		}
		panic(err)
	}
}

func (a *App) Run() error {
	const op = "httpapp.Run"
	log := a.log.With(slog.String("op", op), slog.String("port", a.bindAddr))
	log.Info("Starting HTTP server", slog.String("port", a.bindAddr))
	return a.srv.ListenAndServe()
}

func (a *App) Stop() error {
	const op = "httpapp.Stop"
	log := a.log.With(slog.String("op", op))
	log.Info("Stopping HTTP server", slog.String("port", a.bindAddr))
	ctx, cancel := context.WithTimeout(context.Background(), 15*time.Second)
	defer cancel()
	a.cleanerCancel()
	err := a.srv.Shutdown(ctx)
	if err != nil {
		return err
	}

	log.Info("HTTP server succesfully stopped!")
	return nil
}

package httpApp

import "net/http"

type responseWriter struct {
	code int
	http.ResponseWriter
}

func (w *responseWriter) WriteHeader(statusCode int) {
	w.code = statusCode
	w.ResponseWriter.WriteHeader(statusCode)
}

package authgrpc

import (
	"context"
	"errors"
	"net/url"
	"os"
	"regexp"

	validation "github.com/go-ozzo/ozzo-validation/v4"
	"github.com/go-ozzo/ozzo-validation/v4/is"
	"github.com/synnfluxx/TrustMeBroID/internal/domain/models"
	"github.com/synnfluxx/TrustMeBroID/internal/services/auth"
	"github.com/synnfluxx/TrustMeBroID/internal/storage"
	ssov1 "gitlab.com/synnfluxx/protos/sso/gen"

	"google.golang.org/grpc"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/status"
)

const (
	emptyValue  = 0
	emptyString = ""
)

var PassErr = errors.New("password must be at least 8 characters long and include at least one uppercase letter and one number")

type Auth interface {
	Login(ctx context.Context, identifier models.UserIdentifier, password string, appID int64) (accessToken, refreshToken string, err error)
	RegisterNewUser(ctx context.Context, email string, username string, password string, appID int64) (userID int64, err error)
	IsAdmin(ctx context.Context, userID int64, appID int64) (bool, error)
	RegisterApp(ctx context.Context, appName, redirectURI string) (appID int64, secret string, err error)
	DeleteUser(ctx context.Context, identifier models.UserIdentifier, appID int64) error
	DeleteAdmin(ctx context.Context, identifier models.UserIdentifier, appID int64) error
	DeleteApp(ctx context.Context, appID int64) error
	RefreshToken(ctx context.Context, refreshToken string) (string, error)
	UpdateRefreshToken(ctx context.Context, token string) (string, error)
	MakeAdmin(ctx context.Context, userID, appID int64) (int64, error)
	Logout(ctx context.Context, token string) error
}

type serverAPI struct {
	ssov1.UnimplementedAuthServer
	auth Auth
}

func Register(gRPC *grpc.Server, auth Auth) {
	ssov1.RegisterAuthServer(gRPC, &serverAPI{auth: auth})
}

func (s *serverAPI) MakeAdmin(ctx context.Context, req *ssov1.MakeAdminRequest) (*ssov1.MakeAdminResponse, error) {
	uid, err := s.auth.MakeAdmin(ctx, req.GetUserId(), req.GetAppId())
	if err != nil {
		return nil, status.Error(codes.InvalidArgument, err.Error())
	}

	return &ssov1.MakeAdminResponse{
		UserId: uid,
	}, nil
}

func (s *serverAPI) Login(ctx context.Context, req *ssov1.LoginRequest) (*ssov1.LoginResponse, error) {
	if req.GetAppId() == emptyValue {
		return nil, status.Error(codes.InvalidArgument, "app_id is required")
	}
	switch req.Identifier.(type) {
	case *ssov1.LoginRequest_Email:
		email := req.GetEmail()
		if err := validate(email, req.GetPassword()); err != nil {
			return nil, status.Error(codes.InvalidArgument, err.Error())
		}

		accessToken, refreshToken, err := s.auth.Login(ctx, models.UserIdentifier{Email: &email}, req.GetPassword(), req.GetAppId())
		if err != nil {
			if errors.Is(err, auth.ErrInvalidCredentials) || errors.Is(err, auth.ErrInvalidIdentifier) {
				return nil, status.Error(codes.NotFound, auth.ErrInvalidCredentials.Error())
			}
			if errors.Is(err, storage.ErrAppNotFound) {
				return nil, status.Error(codes.NotFound, "app not found")
			}
			if errors.Is(err, storage.ErrUserNotFound) {
				return nil, status.Error(codes.NotFound, "user not found")
			}

			return nil, status.Error(codes.Internal, "internal error")
		}

		return &ssov1.LoginResponse{
			RefreshToken: refreshToken,
			AccessToken:  accessToken,
		}, nil
	case *ssov1.LoginRequest_Username:
		username := req.GetUsername()
		if err := validate("", req.GetPassword()); err != nil {
			return nil, status.Error(codes.InvalidArgument, err.Error())
		}

		accessToken, refreshToken, err := s.auth.Login(ctx, models.UserIdentifier{Username: &username}, req.GetPassword(), req.GetAppId())
		if err != nil {
			if errors.Is(err, auth.ErrInvalidCredentials) || errors.Is(err, auth.ErrInvalidIdentifier) {
				return nil, status.Error(codes.NotFound, auth.ErrInvalidCredentials.Error())
			}
			if errors.Is(err, storage.ErrAppNotFound) {
				return nil, status.Error(codes.NotFound, "app not found")
			}
			if errors.Is(err, storage.ErrUserNotFound) {
				return nil, status.Error(codes.NotFound, "user not found")
			}

			return nil, status.Error(codes.Internal, "internal error")
		}

		return &ssov1.LoginResponse{
			RefreshToken: refreshToken,
			AccessToken:  accessToken,
		}, nil
	default:
		return nil, status.Error(codes.InvalidArgument, "invalid identifier")
	}
}

func (s *serverAPI) RefreshToken(ctx context.Context, req *ssov1.RefreshTokenRequest) (*ssov1.RefreshTokenResponse, error) {
	token, err := s.auth.RefreshToken(ctx, req.GetRefreshToken())
	if err != nil {
		return nil, status.Error(codes.InvalidArgument, err.Error())
	}

	return &ssov1.RefreshTokenResponse{
		NewToken: token,
	}, nil
}

func (s *serverAPI) Register(ctx context.Context, req *ssov1.RegisterRequest) (*ssov1.RegisterResponse, error) {
	if err := validate(req.GetEmail(), req.GetPassword()); err != nil {
		return nil, status.Error(codes.InvalidArgument, err.Error())
	}

	if req.GetUsername() == emptyString {
		return nil, status.Error(codes.InvalidArgument, "username is required")
	}

	userID, err := s.auth.RegisterNewUser(ctx, req.GetEmail(), req.GetUsername(), req.GetPassword(), req.GetAppId())
	if err != nil {
		if errors.Is(err, auth.ErrUserExists) {
			return nil, status.Error(codes.AlreadyExists, "user already exists")
		}

		return nil, status.Error(codes.Internal, "internal error")
	}

	return &ssov1.RegisterResponse{
		UserId: userID,
	}, nil
}

func (s *serverAPI) IsAdmin(ctx context.Context, req *ssov1.IsAdminRequest) (*ssov1.IsAdminResponse, error) {
	if req.GetUserId() == emptyValue {
		return nil, status.Error(codes.InvalidArgument, "user_id is required")
	}

	isAdmin, err := s.auth.IsAdmin(ctx, req.GetUserId(), req.GetAppId())
	if err != nil {
		if errors.Is(err, storage.ErrUserNotFound) {
			return nil, status.Error(codes.InvalidArgument, "invalid credentials")
		}

		if errors.Is(err, storage.ErrAppNotFound) {
			return nil, status.Error(codes.InvalidArgument, "invalid credentials")
		}

		return nil, status.Error(codes.Internal, "internal error")
	}

	return &ssov1.IsAdminResponse{
		IsAdmin: isAdmin,
	}, nil
}

func (s *serverAPI) RegisterApp(ctx context.Context, req *ssov1.RegisterAppRequest) (*ssov1.RegisterAppResponse, error) {
	if !validateRedirectURI(req.GetRedirectUri(), os.Getenv("ENV")) {
		return nil, status.Error(codes.InvalidArgument, "invalid redirect_uri")
	}

	appID, secret, err := s.auth.RegisterApp(ctx, req.GetAppName(), req.GetRedirectUri())
	if err != nil {
		if errors.Is(err, auth.ErrAppExists) {
			return nil, status.Error(codes.AlreadyExists, "app already exists")
		}

		return nil, status.Error(codes.Internal, "internal server error")
	}

	return &ssov1.RegisterAppResponse{
		AppId:  appID,
		Secret: secret,
	}, nil
}

func (s *serverAPI) DeleteUser(ctx context.Context, req *ssov1.DeleteUserRequest) (*ssov1.Empty, error) {
	if req.GetAppId() == emptyValue {
		return nil, status.Error(codes.InvalidArgument, "app_id is required")
	}

	switch req.Identifier.(type) {
	case *ssov1.DeleteUserRequest_Email:
		email := req.GetEmail()
		err := s.auth.DeleteUser(ctx, models.UserIdentifier{Email: &email}, req.GetAppId())
		if err != nil {
			if errors.Is(err, storage.ErrUserNotFound) {
				return nil, status.Error(codes.InvalidArgument, "invalid credentials")
			}

			return nil, status.Error(codes.Internal, "internal error")
		}

		return &ssov1.Empty{}, nil
	case *ssov1.DeleteUserRequest_Username:
		username := req.GetUsername()
		err := s.auth.DeleteUser(ctx, models.UserIdentifier{Username: &username}, req.GetAppId())
		if err != nil {
			if errors.Is(err, storage.ErrUserNotFound) {
				return nil, status.Error(codes.InvalidArgument, "invalid credentials")
			}

			return nil, status.Error(codes.Internal, "internal error")
		}

		return &ssov1.Empty{}, nil
	case *ssov1.DeleteUserRequest_UserId:
		userID := req.GetUserId()
		err := s.auth.DeleteUser(ctx, models.UserIdentifier{ID: &userID}, req.GetAppId())
		if err != nil {
			if errors.Is(err, storage.ErrUserNotFound) {
				return nil, status.Error(codes.InvalidArgument, "invalid credentials")
			}

			return nil, status.Error(codes.Internal, "internal error")
		}

		return &ssov1.Empty{}, nil
	default:
		return nil, status.Error(codes.InvalidArgument, "invalid identifier")
	}
}

func (s *serverAPI) Logout(ctx context.Context, req *ssov1.LogoutRequest) (*ssov1.Empty, error) { //TODO: DONT tested
	if req.GetRefreshToken() == "" {
		return nil, status.Error(codes.InvalidArgument, "refresh_token is required")
	}

	if err := s.auth.Logout(ctx, req.GetRefreshToken()); err != nil {
		return nil, status.Error(codes.Internal, "internal server error")
	}

	return &ssov1.Empty{}, nil
}

func (s *serverAPI) DeleteAdmin(ctx context.Context, req *ssov1.DeleteAdminRequest) (*ssov1.Empty, error) {
	if req.GetAppId() == emptyValue {
		return nil, status.Error(codes.InvalidArgument, "app_id is required")
	}

	switch req.Identifier.(type) {
	case *ssov1.DeleteAdminRequest_Email:
		email := req.GetEmail()
		err := s.auth.DeleteAdmin(ctx, models.UserIdentifier{Email: &email}, req.GetAppId())
		if err != nil {
			if errors.Is(err, storage.ErrUserNotFound) {
				return nil, status.Error(codes.InvalidArgument, "invalid credentials")
			}

			return nil, status.Error(codes.Internal, "internal server error")
		}

		return &ssov1.Empty{}, nil
	case *ssov1.DeleteAdminRequest_Username:
		username := req.GetUsername()
		err := s.auth.DeleteAdmin(ctx, models.UserIdentifier{Username: &username}, req.GetAppId())
		if err != nil {
			if errors.Is(err, storage.ErrUserNotFound) {
				return nil, status.Error(codes.InvalidArgument, "invalid credentials")
			}

			return nil, status.Error(codes.Internal, "internal server error")
		}

		return &ssov1.Empty{}, nil
	case *ssov1.DeleteAdminRequest_UserId:
		userID := req.GetUserId()
		err := s.auth.DeleteAdmin(ctx, models.UserIdentifier{ID: &userID}, req.GetAppId())
		if err != nil {
			if errors.Is(err, storage.ErrUserNotFound) {
				return nil, status.Error(codes.InvalidArgument, "invalid credentials")
			}

			return nil, status.Error(codes.Internal, "internal server error")
		}

		return &ssov1.Empty{}, nil
	default:
		return nil, status.Error(codes.InvalidArgument, "invalid identifier")
	}
}

func (s *serverAPI) DeleteApp(ctx context.Context, req *ssov1.DeleteAppRequest) (*ssov1.Empty, error) {
	err := s.auth.DeleteApp(ctx, req.GetAppId())
	if err != nil {
		if errors.Is(err, storage.ErrAppNotFound) {
			return nil, status.Error(codes.InvalidArgument, "invalid app_id")
		}

		return nil, status.Error(codes.Internal, "internal error")
	}

	return &ssov1.Empty{}, nil
}

func (s *serverAPI) UpdateRefreshToken(ctx context.Context, req *ssov1.UpdateRefreshTokenRequst) (*ssov1.UpdateRefreshTokenResponse, error) {
	token, err := s.auth.UpdateRefreshToken(ctx, req.GetRefreshToken())
	if err != nil {
		if errors.Is(err, storage.ErrTokenNotFound) {
			return nil, status.Error(codes.InvalidArgument, "refresh token not found")
		}

		return nil, status.Error(codes.Internal, "internal error")
	}

	return &ssov1.UpdateRefreshTokenResponse{
		RefreshToken: token,
	}, nil
}

func validate(email, password string) error {
	if email != "" {
		if err := validation.Validate(email, validation.Required, is.Email); err != nil {
			return err
		}
	}
	if err := validation.Validate(password, validation.Required, validation.Length(8, 32), validation.Match(regexp.MustCompile(`[0-9]`)), validation.Match(regexp.MustCompile(`[A-Z]`))); err != nil {
		return PassErr
	}

	return nil
}

func validateRedirectURI(uri string, env string) bool {
	u, err := url.Parse(uri)
	if err != nil {
		return false
	}

	if env == "prod" {
		if u.Scheme != "https" {
			return false
		}
	} else {
		if u.Scheme != "http" && u.Scheme != "https" {
			return false
		}
	}

	if u.Host == "" {
		return false
	}

	if u.User != nil {
		return false
	}

	if u.Fragment != "" {
		return false
	}

	return true
}

