func TestLogin(t *testing.T) {
	tests := []struct {
		name      string
		req       *ssov1.LoginRequest
		mockSetup func(m *MockAuth)
		wantCode  codes.Code
		wantErr   bool
	}{
		{
			name: "success email exact identifier",
			req: &ssov1.LoginRequest{
				AppId: 1,
				Identifier: &ssov1.LoginRequest_Email{
					Email: "test@mail.com",
				},
				Password: "Password1",
			},
			mockSetup: func(m *MockAuth) {
				m.On("Login",
					mock.Anything,
					mock.MatchedBy(func(id models.UserIdentifier) bool {
						return id.Email != nil && *id.Email == "test@mail.com"
					}),
					"Password1",
					int64(1),
				).Return("access", "refresh", nil)
			},
			wantCode: codes.OK,
		},
		{
			name: "success username",
			req: &ssov1.LoginRequest{
				AppId: 1,
				Identifier: &ssov1.LoginRequest_Username{
					Username: "user123",
				},
				Password: "Password1",
			},
			mockSetup: func(m *MockAuth) {
				m.On("Login",
					mock.Anything,
					mock.MatchedBy(func(id models.UserIdentifier) bool {
						return id.Username != nil && *id.Username == "user123"
					}),
					"Password1",
					int64(1),
				).Return("access", "refresh", nil)
			},
			wantCode: codes.OK,
		},
		{
			name: "invalid credentials",
			req: &ssov1.LoginRequest{
				AppId: 1,
				Identifier: &ssov1.LoginRequest_Email{
					Email: "bad@mail.com",
				},
				Password: "Password1",
			},
			mockSetup: func(m *MockAuth) {
				m.On("Login", mock.Anything, mock.Anything, "Password1", int64(1)).
					Return("", "", auth.ErrInvalidCredentials)
			},
			wantCode: codes.NotFound,
			wantErr:  true,
		},
		{
			name: "invalid password format",
			req: &ssov1.LoginRequest{
				AppId: 1,
				Identifier: &ssov1.LoginRequest_Email{
					Email: "test@mail.com",
				},
				Password: "123",
			},
			mockSetup: func(m *MockAuth) {},
			wantCode:  codes.InvalidArgument,
			wantErr:   true,
		},
		{
			name: "missing app_id",
			req: &ssov1.LoginRequest{
				AppId: 0,
			},
			mockSetup: func(m *MockAuth) {},
			wantCode:  codes.InvalidArgument,
			wantErr:   true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			m := new(MockAuth)
			tt.mockSetup(m)

			s := &serverAPI{auth: m}

			resp, err := s.Login(context.Background(), tt.req)

			if tt.wantErr {
				require.Error(t, err)
				st, _ := status.FromError(err)
				require.Equal(t, tt.wantCode, st.Code())
				return
			}

			require.NoError(t, err)
			require.NotNil(t, resp)

			m.AssertExpectations(t)
		})
	}
}

func TestDeleteUser(t *testing.T) {
	tests := []struct {
		name      string
		req       *ssov1.DeleteUserRequest
		mockSetup func(m *MockAuth)
		wantCode  codes.Code
