func TestStorage_SaveAndFind(t *testing.T) {
	storage, ctx := newTestStorage(t)

	t.Run("save user in non-existing app", func(t *testing.T) {
		_, err := storage.SaveUser(ctx, email, username, []byte(passHash), 1337)
		assert.Error(t, err)
		assert.True(t, errors.Is(err, strg.ErrAppNotFound))
	})

	appID := createTestApp(t, storage, ctx)

	t.Run("duplicate app registration", func(t *testing.T) {
		_, err := storage.RegisterApp(ctx, appName, appSecret, redirectURI)
		assert.Error(t, err)
		assert.True(t, errors.Is(err, strg.ErrAppExists))
	})

	userID := createTestUser(t, storage, ctx, appID)

	t.Run("duplicate save user", func(t *testing.T) {
		_, err := storage.SaveUser(ctx, email, username, []byte(passHash), appID)
		assert.Error(t, err)
		assert.True(t, errors.Is(err, strg.ErrUserExists))
	})

	t.Run("find user by username", func(t *testing.T) {
		user, err := storage.UserByUsername(ctx, username, appID)
		assert.NoError(t, err)
		assert.Equal(t, userID, user.ID)
		assert.Equal(t, email, user.Email)
	})

	t.Run("find user by email", func(t *testing.T) {
		user, err := storage.UserByEmail(ctx, email, appID)
		assert.NoError(t, err)
		assert.Equal(t, userID, user.ID)
		assert.Equal(t, username, user.Username)
	})
}

package handlers

import (
	"encoding/json"
	"log/slog"
	"net/http"
	"time"
)

type Server struct {
	log             *slog.Logger
	accessTokenTTL  time.Duration
	refreshTokenTTL time.Duration
	OAuth           OAuthService
}

func NewHTTPOAuthServer(oauthService OAuthService, log *slog.Logger, accessTokenTTL, refreshTokenTTL time.Duration) *Server {
	return &Server{
		log:             log,
		accessTokenTTL:  accessTokenTTL,
		refreshTokenTTL: refreshTokenTTL,
		OAuth:           oauthService,
	}
}

func (s *Server) jsonResponce(w http.ResponseWriter, status int, payload any) {
	resp, err := json.Marshal(payload)
	if err != nil {
		w.WriteHeader(http.StatusInternalServerError)
		w.Write([]byte(err.Error()))
		return
	}
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	w.Write([]byte(resp))
}

func (s *Server) respondError(w http.ResponseWriter, code int, message string) {
	s.jsonResponce(w, code, map[string]string{"error": message})
}

package handlers

import (
	"context"
	"errors"
	"fmt"
	"net/http"
	"strconv"
	"strings"
	"time"

	"github.com/synnfluxx/TrustMeBroID/internal/lib/logger/sl"
	"github.com/synnfluxx/TrustMeBroID/internal/storage"
)

type OAuthService interface {
	Login(ctx context.Context, appID int64) (string, string, error)
	Callback(ctx context.Context, code string, appID int64, accessTTL, refreshTTL time.Duration) (accessToken string, refreshToken string, redirectURI string, err error)
}

func (s *Server) LoginHandler() http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		var appID string
		if appID = r.URL.Query().Get("app_id"); appID == "" {
			s.respondError(w, http.StatusBadRequest, "app_id is required")
			return
		}

		aid, err := strconv.Atoi(appID)
		if err != nil {
			s.respondError(w, http.StatusBadRequest, "invalid app_id")
			return
		}

		state, url, err := s.OAuth.Login(r.Context(), int64(aid))
		if err != nil {
			if errors.Is(err, storage.ErrAppNotFound) {
				s.respondError(w, http.StatusBadRequest, "invalid app_id")
				return
			}
		}

		s.setState(w, state)

		http.Redirect(w, r, url, http.StatusTemporaryRedirect)
	}
}

func (s *Server) CallbackHandler() http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		appID, err := s.getAndValidateState(r)
		if err != nil {
			s.log.Warn("state validation error", sl.Err(err))
			s.respondError(w, http.StatusBadRequest, "bad request")
			return
		}

		token, refreshToken, uri, err := s.OAuth.Callback(r.Context(), r.FormValue("code"), appID, s.accessTokenTTL, s.refreshTokenTTL)
		if err != nil {
			s.log.Warn("get tokens error", sl.Err(err))
			s.respondError(w, http.StatusInternalServerError, "internal server error")
			return
		}

		s.setRefershToken(w, refreshToken)
		redirectURL := fmt.Sprintf("%s?token=%s", uri, token)
		http.Redirect(w, r, redirectURL, http.StatusPermanentRedirect)
	}
}

func (s *Server) getAndValidateState(r *http.Request) (int64, error) {
	oauthState, err := r.Cookie("oauth_state")
	if err != nil {
		return 0, err
	}

	state := r.URL.Query().Get("state")
	parts := strings.Split(state, ":")
	if len(parts) < 2 {
		return 0, err
	}

	if len(parts[1]) == 0 {
		return 0, err
	}

	appID, err := strconv.Atoi(parts[1])
	if err != nil {
		return 0, err
	}

	if oauthState.Value != state {
		return 0, err
	}

	return int64(appID), nil
}

func (s *Server) setState(w http.ResponseWriter, state string) {
	cookie := &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		MaxAge:   600,
		SameSite: http.SameSiteLaxMode,
		Secure:   true,
	}
	http.SetCookie(w, cookie)
}

func (s *Server) setRefershToken(w http.ResponseWriter, token string) {
	cookie := &http.Cookie{
		Name:     "refreshToken",
		Value:    token,
		HttpOnly: true,
		SameSite: http.SameSiteLaxMode,
		MaxAge:   int(s.refreshTokenTTL.Seconds()),
		Secure:   true,
	}
	http.SetCookie(w, cookie)
}

package jwt

import (
	"context"
	"fmt"
	"time"

	"github.com/golang-jwt/jwt/v5"
	"github.com/synnfluxx/TrustMeBroID/internal/domain/models"
)

type JWTRepository interface {
	SaveRefreshToken(ctx context.Context, token string, userID int64, appID int64, ttl time.Duration) error
	SetNewRefreshToken(ctx context.Context, oldToken string, newToken string, ttl time.Duration) error
	GetRefreshTokenFields(ctx context.Context, token string) (*models.RefreshTokenFields, error)
}

type OAuthCustomClaims struct {
	AvatarPath string `json:"avatar_path"`
	jwt.RegisteredClaims
}

func NewAccessToken(userID, appID int64, accessDuration time.Duration, appSecret string) (accessToken string, err error) {
	claims := &jwt.RegisteredClaims{
		Issuer:    fmt.Sprint(appID),
		Subject:   fmt.Sprint(userID),
		IssuedAt:  jwt.NewNumericDate(time.Now()),
		ExpiresAt: jwt.NewNumericDate(time.Now().Add(accessDuration)),
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	accessToken, err = token.SignedString([]byte(appSecret))
	if err != nil {
		return accessToken, err
	}

	return accessToken, err
}

func NewOAuthAccessToken(userID, appID int64, accessDuration time.Duration, appSecret, avatarPath string) (accessToken string, err error) {
	claims := &OAuthCustomClaims{
		AvatarPath: avatarPath,
		RegisteredClaims: jwt.RegisteredClaims{
			Issuer:    fmt.Sprint(appID),
			Subject:   fmt.Sprint(userID),
			IssuedAt:  jwt.NewNumericDate(time.Now()),
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(accessDuration)),	
		},
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	accessToken, err = token.SignedString([]byte(appSecret))
	if err != nil {
		return accessToken, err
	}

	return accessToken, err
}

func NewRefreshToken(userID, appID int64, refreshDuration time.Duration, appSecret string) (refreshToken string, err error) {
	claims := &jwt.RegisteredClaims{
		Issuer:    fmt.Sprint(appID),
		Subject:   fmt.Sprint(userID),
		IssuedAt:  jwt.NewNumericDate(time.Now()),
		ExpiresAt: jwt.NewNumericDate(time.Now().Add(refreshDuration)),
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	refreshToken, err = token.SignedString([]byte(appSecret))
	if err != nil {
		return refreshToken, err
	}

	return refreshToken, err
}

func NewTokens(userID, appID int64, appSecret string, refreshDuration, accessDuration time.Duration) (accessToken, refreshToken string, err error) {
	refreshToken, err = NewRefreshToken(userID, appID, refreshDuration, appSecret)
	if err != nil {
		return "", "", err
	}

	accessToken, err = NewAccessToken(userID, appID, accessDuration, appSecret)
	if err != nil {
		return "", "", err
	}

	return accessToken, refreshToken, err
}

func NewOAuthTokens(userID, appID int64, appSecret, avatarPath string, refreshDuration, accessDuration time.Duration) (accessToken, refreshToken string, err error) {
	refreshToken, err = NewRefreshToken(userID, appID, refreshDuration, appSecret)
	if err != nil {
		return "", "", err
	}

	accessToken, err = NewOAuthAccessToken(userID, appID, accessDuration, appSecret, avatarPath)
	if err != nil {
		return "", "", err
	}

	return accessToken, refreshToken, err
}

