package encryptor

import (
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestE2E_EncryptDecryptString(t *testing.T) {
	testCases := []struct {
		name        string
		masterkey   string
		data        string
		isValid     bool
		expectedErr error
	}{
		{
			name:      "success",
			masterkey: "1234567890123456", // len = 16
			data:      "secret information",
			isValid:   true,
		},
		{
			name:        "invalid masterkey",
			masterkey:   "12345",
			data:        "sss",
			isValid:     false,
			expectedErr: lenErr,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			if tc.isValid {
				s, err := EncryptString([]byte(tc.masterkey), []byte(tc.data))
				require.NoError(t, err)
				ds, err := DecryptString([]byte(tc.masterkey), s)
				assert.NoError(t, err)
				assert.Equal(t, tc.data, ds)
			} else {
				s, err := EncryptString([]byte(tc.masterkey), []byte(tc.data))
				assert.Error(t, err)
				assert.Equal(t, err, lenErr)
				assert.Empty(t, s)
			}
		})
	}
}

package encryptor

import (
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"encoding/base64"
	"errors"
	"io"

	"golang.org/x/crypto/bcrypt"
)

var lenErr = errors.New("masterkey must be 16, 24 or 32 characters")

func EncryptString(masterkey []byte, data []byte) (string, error) {
	switch len(masterkey) {
	case 16, 24, 32:
	default:
		return "", lenErr
	}

	block, err := aes.NewCipher(masterkey)
	if err != nil {
		return "", err
	}

	aesGSM, err := cipher.NewGCM(block)
	if err != nil {
		return "", err
	}

	nonce := make([]byte, aesGSM.NonceSize())
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		return "", err
	}

	seal := aesGSM.Seal(nonce, nonce, data, nil)

	return base64.StdEncoding.EncodeToString(seal), nil
}

func DecryptString(masterkey []byte, encoded string) (string, error) {
	switch len(masterkey) {
	case 16, 24, 32:
	default:
		return "", lenErr
	}

	cipherText, err := base64.StdEncoding.DecodeString(encoded)
	if err != nil {
		return "", err
	}

	block, err := aes.NewCipher(masterkey)
	if err != nil {
		return "", err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return "", err
	}

	nonceSize := gcm.NonceSize()
	nonce := cipherText[:nonceSize]
	data := cipherText[nonceSize:]

	plainText, err := gcm.Open(nil, nonce, data, nil)
	if err != nil {
		return "", err
	}

	return string(plainText), nil
}

type PasswordHasher struct {}

func NewPasswordHasher() *PasswordHasher {
	return &PasswordHasher{}
}

func (ph *PasswordHasher) Compare(hash []byte, pw []byte) error {
	return bcrypt.CompareHashAndPassword(hash, pw)
}

