package oauth

import (
	"context"
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"log/slog"
	"time"

	"github.com/synnfluxx/TrustMeBroID/internal/domain/models"
	"github.com/synnfluxx/TrustMeBroID/internal/lib/jwt"
	"github.com/synnfluxx/TrustMeBroID/internal/lib/logger/sl"
)

type Storage interface {
	FindOrCreateOAuthUser(ctx context.Context, email, username string, appID int64) (usr models.User, err error)
	App(ctx context.Context, appID int64) (models.App, error)
	UserByEmail(ctx context.Context, email string, appID int64) (models.User, error)
}

type TokenProvider interface {
	SaveRefreshToken(ctx context.Context, token string, userID int64, appID int64, ttl time.Duration) error
}

type OAuthConfig interface {
	URL(state string) string
	Callback(ctx context.Context, code string) (*OAuthUserDetails, error)
}

type OAuthUserDetails struct {
	Email    string
	Username string
	Avatar   string
}

type OAuthService struct {
	config        OAuthConfig
	storage       Storage
	tokenProvider TokenProvider
	log           *slog.Logger
}

func New(OAuthConfig OAuthConfig, storage Storage, rdb TokenProvider, log *slog.Logger) *OAuthService {
	return &OAuthService{
		config:        OAuthConfig,
		storage:       storage,
		tokenProvider: rdb,
		log:           log,
	}
}

func (o *OAuthService) Login(ctx context.Context, appID int64) (state string, url string, err error) { // Provider url for permission ask
	_, err = o.storage.App(ctx, appID)
	if err != nil {
		return "", "", err
	}

	b := make([]byte, 16)
	rand.Read(b)
	state = fmt.Sprintf("%s:%d", hex.EncodeToString(b), appID)

	return state, o.config.URL(state), nil
}

func (o *OAuthService) Callback(ctx context.Context, code string, appID int64, accessTTL, refreshTTL time.Duration) (accessToken string, refreshToken string, redirectURI string, err error) {
	oauthUser, err := o.config.Callback(ctx, code)
	if err != nil {
		return "", "", "", err
	}

	usr, err := o.storage.FindOrCreateOAuthUser(ctx, oauthUser.Email, oauthUser.Username, appID)
	if err != nil {
		o.log.Warn("github oauth callback save user error: ", sl.Err(err))
		return "", "", "", err
	}

	app, err := o.storage.App(ctx, appID)
	if err != nil {
		o.log.Warn("github oauth callback get app error: ", sl.Err(err))
		return "", "", "", err
	}

	accessToken, refreshToken, err = jwt.NewOAuthTokens(usr.ID, app.ID, app.Secret, oauthUser.Avatar, refreshTTL, accessTTL)
	if err != nil {
		o.log.Warn("oauth callback get jwt token error: ", sl.Err(err))
		return "", "", "", err
	}

	err = o.tokenProvider.SaveRefreshToken(ctx, refreshToken, usr.ID, int64(appID), refreshTTL)
	if err != nil {
		o.log.Warn("save refresh token error", sl.Err(err))
		return "", "", "", err
	}

	return accessToken, refreshToken, app.RedirectURI, nil
}

package oauth

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"os"

	"golang.org/x/oauth2"
)

type GithubOAuth struct {
	config     *oauth2.Config
	userAPIURL string
}

type GithubUser struct {
	Email      string `json:"email"`
	Username   string `json:"login"`
	AvatarPath string `json:"avatar_url"`
}

type GithubEmail struct {
	Email    string `json:"email"`
	Primary  bool   `json:"primary"`
	Verified bool   `json:"verified"`
}

func NewGithubConfig() *GithubOAuth {
	return &GithubOAuth{
		config: &oauth2.Config{
			RedirectURL:  fmt.Sprintf("%s/auth/github/callback", os.Getenv("BASE_URL")),
			ClientID:     os.Getenv("GITHUB_CLIENT_ID"),
			ClientSecret: os.Getenv("GITHUB_CLIENT_SECRET"),
			Endpoint: oauth2.Endpoint{
				AuthURL:  "https://github.com/login/oauth/authorize",
				TokenURL: "https://github.com/login/oauth/access_token",
			},
			Scopes: []string{"user:email", "read:user"},
		},
		userAPIURL: "https://api.github.com/user",
	}
}

func (g *GithubOAuth) URL(state string) string {
	return g.config.AuthCodeURL(state)
}

func (g *GithubOAuth) Callback(ctx context.Context, code string) (*OAuthUserDetails, error) {
	const op = "oauth.GitHubOAuthCallback"
	usr, err := g.getUserDataFromGitHub(ctx, code)
	if err != nil {
		return nil, fmt.Errorf("%s: %w", op, err)
	}

	return &OAuthUserDetails{
		Email:    usr.Email,
		Username: usr.Username,
		Avatar:   usr.AvatarPath,
	}, nil
}

func (g *GithubOAuth) getUserDataFromGitHub(ctx context.Context, code string) (*GithubUser, error) {
	token, err := g.config.Exchange(ctx, code)
	if err != nil {
		return nil, err
	}

	client := g.config.Client(ctx, token)
	resp, err := client.Get(g.userAPIURL)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	usr := &GithubUser{}
	if err := json.NewDecoder(resp.Body).Decode(&usr); err != nil {
		return nil, err
	}

	if usr.Email == "" {
		email, err := g.getUserEmail(ctx, client)
		if err != nil {
			return nil, err
		}
		usr.Email = email
	}

	return usr, err
}

func (g *GithubOAuth) getUserEmail(ctx context.Context, client *http.Client) (string, error) {
	resp, err := client.Get("https://api.github.com/user/emails")
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return "", fmt.Errorf("github api user/emails returned status %d", resp.StatusCode)
	}

	var emails []GithubEmail
	if err := json.NewDecoder(resp.Body).Decode(&emails); err != nil {
		return "", err
	}

	for _, email := range emails {
		if email.Primary && email.Verified {
			return email.Email, nil
		}
	}

	if len(emails) > 0 {
		return emails[0].Email, nil
	}

	return "", fmt.Errorf("no email found")
}

